    // Feature 3: Account Usage Statistics Dashboard,


    showUsageDashboardEnhanced: function() {
        const user = store.state.user || {};
        const inventory = store.state.inventory || [];
        const images = store.state.images || [];

        // Calculate storage usage
        const estimatedStorageGB = (images.length * 0.002) + 0.1;
        const storageLimit = 5;
        const storagePercent = Math.min(100, (estimatedStorageGB / storageLimit) * 100);

        // Mock API usage
        const apiUsagePercent = 35;

        // Get account age
        const createdDate = user.created_at ? new Date(user.created_at) : new Date();
        const today = new Date();
        const accountAgeMs = today - createdDate;
        const accountAgeDays = Math.floor(accountAgeMs / (1000 * 60 * 60 * 24));

        // Mock active sessions
        const activeSessions = 2;

        const getColorStatus = (percent) => {
            if (percent > 95) return { color: '#ef4444', status: 'danger' };
            if (percent > 80) return { color: '#f59e0b', status: 'warning' };
            return { color: '#10b981', status: 'success' };
        };

        const renderUsageMetric = (label, value, limit, percent, unit = '') => {
            const colorInfo = getColorStatus(percent);
            return `
                <div class="usage-metric-card">
                    <div class="usage-metric-header">
                        <h5 class="usage-metric-label">${escapeHtml(label)}</h5>
                        <span class="usage-metric-value">${value} / ${limit} ${unit}</span>
                    </div>
                    <div class="usage-metric-bar-container">
                        <div class="usage-metric-bar-fill" style="width: ${percent}%; background-color: ${colorInfo.color};"></div>
                    </div>
                    <span class="usage-metric-percent" style="color: ${colorInfo.color}; font-weight: 600;">${Math.round(percent)}%</span>
                </div>
            `;
        };

        modals.show(`
            <div class="modal-header">
                <h2 class="modal-title">Account Usage Statistics</h2>
                <button class="modal-close" aria-label="Close" onclick="modals.close()">${components.icon('close')}</button>
            </div>
            <div class="modal-body">
                <div class="usage-stats-container">
                    <div class="usage-stats-grid">
                        <div class="usage-stat-item">
                            <span class="usage-stat-label">Inventory Items</span>
                            <span class="usage-stat-value">${inventory.length}</span>
                        </div>
                        <div class="usage-stat-item">
                            <span class="usage-stat-label">Total Images</span>
                            <span class="usage-stat-value">${images.length}</span>
                        </div>
                        <div class="usage-stat-item">
                            <span class="usage-stat-label">Active Sessions</span>
                            <span class="usage-stat-value">${activeSessions}</span>
                        </div>
                        <div class="usage-stat-item">
                            <span class="usage-stat-label">Account Age</span>
                            <span class="usage-stat-value">${accountAgeDays} days</span>
                        </div>
                    </div>

                    <div class="usage-metrics">
                        ${renderUsageMetric('Storage Usage', estimatedStorageGB.toFixed(2), storageLimit, storagePercent, 'GB')}
                        ${renderUsageMetric('API Requests', 3500, 10000, apiUsagePercent, '')}
                    </div>
                </div>
            </div>
            <div class="modal-footer">
                <button class="btn btn-secondary" onclick="modals.close();">Close</button>
            </div>
        `);
    },

