    // Delete notification with dismiss animation,


    deleteNotification: async function(notificationId) {
        if (await modals.confirm('Are you sure you want to delete this notification?', { title: 'Delete Notification', confirmText: 'Delete', danger: true })) {
            // Animate the notification out
            const items = document.querySelectorAll('.notification-item');
            for (const el of items) {
                if (el.querySelector(`[onclick*="${notificationId}"]`)) {
                    el.classList.add('notification-dismiss');
                    await new Promise(r => setTimeout(r, 300));
                    break;
                }
            }
            const notifications = store.state.notifications.filter(n => n.id !== notificationId);
            store.setState({ notifications });
            handlers.updateTabBadge();
            renderApp(pages.notifications());
        }
    },

