    openGlobalSearch: function() {
        // Create search overlay
        const existingOverlay = document.querySelector('.global-search-overlay');
        if (existingOverlay) {
            existingOverlay.remove();
            return;
        }

        const overlay = document.createElement('div');
        overlay.className = 'global-search-overlay';
        overlay.onclick = (e) => { if (e.target === overlay) overlay.remove(); };

        const searchItems = [
            { type: 'page', title: 'Dashboard', subtitle: 'View your overview', route: 'dashboard', icon: 'dashboard' },
            { type: 'page', title: 'Inventory', subtitle: 'Manage your items', route: 'inventory', icon: 'inventory' },
            { type: 'page', title: 'Listings', subtitle: 'View your listings', route: 'listings', icon: 'list' },
            { type: 'page', title: 'Orders', subtitle: 'Track your orders', route: 'orders', icon: 'sales' },
            { type: 'page', title: 'Automations', subtitle: 'Configure automations', route: 'automations', icon: 'automation' },
            { type: 'page', title: 'Analytics', subtitle: 'View performance data', route: 'analytics', icon: 'analytics' },
            { type: 'page', title: 'Settings', subtitle: 'Configure your account', route: 'settings', icon: 'settings' },
            { type: 'action', title: 'Add New Item', subtitle: 'Add inventory item', action: 'modals.addItem()', icon: 'plus' },
            { type: 'action', title: 'Keyboard Shortcuts', subtitle: 'View all shortcuts', action: 'handlers.showKeyboardShortcuts()', icon: 'help' }
        ];

        overlay.innerHTML = `
            <div class="global-search-modal">
                <div class="global-search-input-wrapper">
                    ${components.icon('search', 20)}
                    <input type="text" class="global-search-input" placeholder="Search pages, actions, or items..." autofocus oninput="handlers.filterGlobalSearch(this.value)">
                    <div class="global-search-shortcut">
                        <span class="keyboard-key">Esc</span>
                    </div>
                </div>
                <div class="global-search-results" id="global-search-results">
                    <div class="global-search-section">
                        <div class="global-search-section-title">Quick Actions</div>
                        ${searchItems.map((item, idx) => `
                            <div class="global-search-item ${idx === 0 ? 'selected' : ''}" data-index="${idx}" onclick="handlers.executeGlobalSearchItem(${idx})">
                                <div class="global-search-item-icon">${components.icon(item.icon, 16)}</div>
                                <div class="global-search-item-content">
                                    <div class="global-search-item-title">${escapeHtml(item.title)}</div>
                                    <div class="global-search-item-subtitle">${escapeHtml(item.subtitle)}</div>
                                </div>
                            </div>
                        `).join('')}
                    </div>
                </div>
                <div class="global-search-footer">
                    <span>↑↓ Navigate</span>
                    <span>↵ Select</span>
                    <span>Esc Close</span>
                </div>
            </div>
        `;

        document.body.appendChild(overlay);

        // Store search items in state for filtering
        store.state.globalSearchItems = searchItems;
        store.state.globalSearchIndex = 0;

        // Handle keyboard navigation
        const input = overlay.querySelector('.global-search-input');
        input.addEventListener('keydown', (e) => {
            const items = overlay.querySelectorAll('.global-search-item');
            let currentIdx = store.state.globalSearchIndex || 0;

            if (e.key === 'Escape') {
                overlay.remove();
            } else if (e.key === 'ArrowDown') {
                e.preventDefault();
                currentIdx = (currentIdx + 1) % items.length;
                store.state.globalSearchIndex = currentIdx;
                items.forEach((item, i) => item.classList.toggle('selected', i === currentIdx));
            } else if (e.key === 'ArrowUp') {
                e.preventDefault();
                currentIdx = (currentIdx - 1 + items.length) % items.length;
                store.state.globalSearchIndex = currentIdx;
                items.forEach((item, i) => item.classList.toggle('selected', i === currentIdx));
            } else if (e.key === 'Enter') {
                e.preventDefault();
                handlers.executeGlobalSearchItem(currentIdx);
            }
        });
    },


    filterGlobalSearch: function(query) {
        const items = store.state.globalSearchItems || [];
        const filtered = query ? items.filter(item =>
            item.title.toLowerCase().includes(query.toLowerCase()) ||
            item.subtitle.toLowerCase().includes(query.toLowerCase())
        ) : items;

        const resultsEl = document.getElementById('global-search-results');
        if (!resultsEl) return;

        resultsEl.innerHTML = `
            <div class="global-search-section">
                <div class="global-search-section-title">${query ? 'Results' : 'Quick Actions'}</div>
                ${filtered.length > 0 ? filtered.map((item, idx) => `
                    <div class="global-search-item ${idx === 0 ? 'selected' : ''}" data-index="${idx}" onclick="handlers.executeGlobalSearchItem(${idx})">
                        <div class="global-search-item-icon">${components.icon(item.icon, 16)}</div>
                        <div class="global-search-item-content">
                            <div class="global-search-item-title">${escapeHtml(item.title)}</div>
                            <div class="global-search-item-subtitle">${item.subtitle}</div>
                        </div>
                    </div>
                `).join('') : '<div class="p-4 text-center text-gray-500">No results found</div>'}
            </div>
        `;

        store.state.globalSearchFiltered = filtered;
        store.state.globalSearchIndex = 0;
    },


    executeGlobalSearchItem: function(index) {
        const items = store.state.globalSearchFiltered || store.state.globalSearchItems || [];
        const item = items[index];
        if (!item) return;

        // Close search overlay
        document.querySelector('.global-search-overlay')?.remove();

        if (item.type === 'page' && item.route) {
            router.navigate(item.route);
        } else if (item.type === 'action' && item.action) {
            // Safely dispatch action instead of eval
            try {
                const fnMatch = item.action.match(/^(\w+(?:\.\w+)*)\((.*)\)$/);
                if (fnMatch) {
                    const fnPath = fnMatch[1].split('.');
                    let fn = window;
                    for (const part of fnPath) fn = fn?.[part];
                    if (typeof fn === 'function') {
                        // Parse arguments from the action string
                        const argsStr = fnMatch[2];
                        const args = argsStr ? argsStr.split(',').map(a => {
                            const trimmed = a.trim();
                            // Handle string literals and identifiers
                            if ((trimmed.startsWith("'") && trimmed.endsWith("'")) ||
                                (trimmed.startsWith('"') && trimmed.endsWith('"'))) {
                                return trimmed.slice(1, -1);
                            }
                            return trimmed;
                        }) : [];
                        fn(...args);
                    }
                }
            } catch (e) {
                console.error('Error executing global search action:', e);
                toast.error('Failed to execute action');
            }
        }
    },


