    showAccountUsage: function() {
        const inventory = store.state.inventory || [];
        const listings = store.state.listings || [];
        const orders = store.state.orders || [];
        const offers = store.state.offers || [];
        const checklistItems = store.state.checklistItems || [];
        const totalSales = orders.filter(o => o.status === 'completed' || o.status === 'shipped' || o.status === 'delivered').length;
        const totalRevenue = orders.filter(o => o.status === 'completed' || o.status === 'shipped' || o.status === 'delivered').reduce((s, o) => s + (o.sale_price || o.price || 0), 0);

        // Platform breakdown
        const platformCounts = {};
        [...inventory, ...listings].forEach(item => {
            const p = item.platform || 'Unknown';
            platformCounts[p] = (platformCounts[p] || 0) + 1;
        });
        const platformEntries = Object.entries(platformCounts).sort((a, b) => b[1] - a[1]);

        // Monthly activity (items added per month, last 6 months)
        const monthData = [];
        const monthNames = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
        for (let m = 5; m >= 0; m--) {
            const date = new Date();
            date.setMonth(date.getMonth() - m);
            const yearMonth = date.getFullYear() + '-' + String(date.getMonth() + 1).padStart(2, '0');
            const count = inventory.filter(i => i.created_at && i.created_at.startsWith(yearMonth)).length;
            monthData.push({ label: monthNames[date.getMonth()], count });
        }
        const maxMonth = Math.max(...monthData.map(d => d.count), 1);

        modals.show(`
            <div class="modal-header">
                <h2 class="modal-title">${components.icon('activity', 20)} Account Usage Statistics</h2>
                <button class="modal-close" aria-label="Close" onclick="modals.close()">${components.icon('close')}</button>
            </div>
            <div class="modal-body account-usage-section">
                <div class="usage-stats-grid">
                    <div class="usage-stat-card">
                        <div class="usage-stat-icon" style="background: var(--primary-100); color: var(--primary-600);">
                            ${components.icon('package', 20)}
                        </div>
                        <div class="usage-stat-value">${inventory.length}</div>
                        <div class="usage-stat-label">Inventory Items</div>
                    </div>
                    <div class="usage-stat-card">
                        <div class="usage-stat-icon" style="background: var(--success-100, #d1fae5); color: var(--success-600, #059669);">
                            ${components.icon('tag', 20)}
                        </div>
                        <div class="usage-stat-value">${listings.length}</div>
                        <div class="usage-stat-label">Active Listings</div>
                    </div>
                    <div class="usage-stat-card">
                        <div class="usage-stat-icon" style="background: var(--warning-100, #fef3c7); color: var(--warning-600, #d97706);">
                            ${components.icon('shopping-cart', 20)}
                        </div>
                        <div class="usage-stat-value">${orders.length}</div>
                        <div class="usage-stat-label">Total Orders</div>
                    </div>
                    <div class="usage-stat-card">
                        <div class="usage-stat-icon" style="background: #ede9fe; color: #7c3aed;">
                            ${components.icon('message-circle', 20)}
                        </div>
                        <div class="usage-stat-value">${offers.length}</div>
                        <div class="usage-stat-label">Total Offers</div>
                    </div>
                    <div class="usage-stat-card">
                        <div class="usage-stat-icon" style="background: #fce7f3; color: #db2777;">
                            ${components.icon('check-circle', 20)}
                        </div>
                        <div class="usage-stat-value">${totalSales}</div>
                        <div class="usage-stat-label">Completed Sales</div>
                    </div>
                    <div class="usage-stat-card">
                        <div class="usage-stat-icon" style="background: #ecfdf5; color: #059669;">
                            ${components.icon('dollar-sign', 20)}
                        </div>
                        <div class="usage-stat-value">$${totalRevenue.toLocaleString()}</div>
                        <div class="usage-stat-label">Total Revenue</div>
                    </div>
                </div>

                ${platformEntries.length > 0 ? `
                <div class="platform-usage-section">
                    <h4>Platform Breakdown</h4>
                    <div class="platform-usage-list">
                        ${platformEntries.map(([platform, count]) => {
                            const pct = Math.round((count / (inventory.length + listings.length)) * 100);
                            return '<div class="platform-usage-row">' +
                                '<div class="platform-usage-name">' + escapeHtml(platform) + '</div>' +
                                '<div class="priority-bar-track">' +
                                    '<div class="priority-bar priority-bar-primary" style="width: ' + pct + '%"></div>' +
                                '</div>' +
                                '<span class="platform-usage-count">' + count + ' items (' + pct + '%)</span>' +
                            '</div>';
                        }).join('')}
                    </div>
                </div>
                ` : ''}

                <div class="monthly-activity-section">
                    <h4>Monthly Activity (Items Added)</h4>
                    <div class="trend-chart">
                        ${monthData.map(d => `
                            <div class="trend-bar-group">
                                <div class="trend-bar-container">
                                    <div class="trend-bar" style="height: ${d.count > 0 ? Math.max((d.count / maxMonth) * 100, 8) : 4}%"></div>
                                </div>
                                <span class="trend-bar-count">${d.count}</span>
                                <span class="trend-bar-label">${d.label}</span>
                            </div>
                        `).join('')}
                    </div>
                </div>
            </div>
            <div class="modal-footer">
                <button class="btn btn-secondary" onclick="modals.close()">Close</button>
            </div>
        `, 'modal-md');
    },

